mapper.select:
SELECT ta.application_id, ta.student_id, s.real_name AS studentName, s.account AS studentAccount, ta.topic_id, tl.topic_name, ta.team_id, ta.apply_type, ta.application_status, ta.apply_time, ta.review_time, ta.remark FROM thesis_application ta LEFT JOIN student_account s ON ta.student_id = s.student_id LEFT JOIN topic_library tl ON ta.topic_id = tl.topic_id
AND ta.application_status = #{status}
ORDER BY ta.apply_time DESC LIMIT #{limit} OFFSET #{offset}
